# torch_ios: pure-Python `safetensors` implementation.
#
# Real safetensors is Rust + PyO3 — we haven't cross-compiled for iOS arm64.
# But the on-disk format is documented and trivially simple, so this shim
# implements the *reading* path natively in Python. That's enough to let
# `transformers.from_pretrained(...)` load any model that ships its weights
# as `.safetensors` (which is most modern HF models).
#
# On-disk format:
#   [8 bytes : little-endian u64 — JSON header length, call it N]
#   [N bytes  : UTF-8 JSON describing each tensor: dtype/shape/data_offsets]
#   [rest     : raw tensor bytes, sliced per JSON's data_offsets]
#
# We mmap the file so large model loads don't double-copy into RAM.
# Writing is NOT implemented — adding it is a few more lines but the
# current iOS use cases are read-only inference / fine-tune.

from __future__ import annotations
import json
import mmap
import os
import struct
from typing import Iterator

__version__ = "0.4.5"


class SafetensorError(Exception):
    pass


# Map safetensors dtype strings → (numpy/torch dtype name, element byte size)
_DTYPE_MAP = {
    "F32":  ("float32", 4),
    "F16":  ("float16", 2),
    "BF16": ("bfloat16", 2),
    "F64":  ("float64", 8),
    "I8":   ("int8", 1),
    "U8":   ("uint8", 1),
    "I16":  ("int16", 2),
    "U16":  ("uint16", 2),
    "I32":  ("int32", 4),
    "U32":  ("uint32", 4),
    "I64":  ("int64", 8),
    "U64":  ("uint64", 8),
    "BOOL": ("bool", 1),
}


class _SafeOpen:
    """Context-manager handle to an open .safetensors file. Returned
    by `safe_open()`. Mirrors the API of the real safetensors lib:
    `.keys()`, `.get_tensor(name)`, `.metadata()`, `.get_slice(name)`."""

    def __init__(self, path: str, framework: str = "pt"):
        self.path = path
        self.framework = framework
        self._fd = open(path, "rb")
        try:
            size = os.fstat(self._fd.fileno()).st_size
            self._mm = mmap.mmap(self._fd.fileno(), size,
                                 prot=mmap.PROT_READ)
        except Exception:
            self._fd.close()
            raise
        # First 8 bytes = JSON header length (little-endian u64).
        if size < 8:
            raise SafetensorError(f"file too small to be safetensors: {size} bytes")
        n = struct.unpack_from("<Q", self._mm, 0)[0]
        if n + 8 > size:
            raise SafetensorError(f"header length {n} > file size {size}")
        try:
            header_json = self._mm[8:8 + n].decode("utf-8")
            self._header = json.loads(header_json)
        except Exception as e:
            raise SafetensorError(f"header parse failed: {e}") from e
        self._data_off = 8 + n     # byte offset where tensor data begins
        # The real lib reserves the `__metadata__` key for non-tensor info.
        self._meta = self._header.pop("__metadata__", {}) or {}

    def __enter__(self): return self
    def __exit__(self, *exc):
        try: self._mm.close()
        except Exception: pass
        try: self._fd.close()
        except Exception: pass

    def keys(self) -> Iterator[str]:
        return iter(self._header.keys())

    def metadata(self) -> dict:
        return dict(self._meta)

    def get_tensor(self, name: str):
        """Return a tensor in the requested framework. Currently
        supports `framework='pt'` (PyTorch) — what transformers asks
        for. Other frameworks (`numpy`, `tf`, `jax`, `flax`) would
        require those libs and aren't wired."""
        if name not in self._header:
            raise KeyError(f"no tensor named {name!r}")
        info = self._header[name]
        dtype_name = info["dtype"]
        shape = info["shape"]
        start, end = info["data_offsets"]
        if dtype_name not in _DTYPE_MAP:
            raise SafetensorError(f"unknown dtype {dtype_name!r}")
        torch_dtype_name, elem_size = _DTYPE_MAP[dtype_name]
        # Sanity check: declared element count × element size must
        # equal the byte slice length.
        nelems = 1
        for d in shape:
            nelems *= d
        expected = nelems * elem_size
        actual = end - start
        if expected != actual:
            raise SafetensorError(
                f"{name}: declared {expected} bytes, slice is {actual}")
        # Slice the mmap directly — zero-copy view.
        raw = bytes(self._mm[self._data_off + start : self._data_off + end])
        if self.framework == "pt":
            return _to_torch(raw, torch_dtype_name, shape)
        if self.framework in ("numpy", "np"):
            return _to_numpy(raw, torch_dtype_name, shape)
        raise SafetensorError(f"framework {self.framework!r} not supported in shim")

    def get_slice(self, name: str):
        """Real safetensors returns a `PySafeSlice` object that lets you
        index into the tensor without materializing it. For the shim we
        just materialize and return — slower but correct."""
        t = self.get_tensor(name)
        return _MaterializedSlice(t)


class _MaterializedSlice:
    def __init__(self, tensor): self._t = tensor
    def get_shape(self): return list(self._t.shape)
    def get_dtype(self): return str(self._t.dtype)
    def __getitem__(self, k): return self._t[k]


def _to_torch(raw_bytes, torch_dtype_name, shape):
    """Construct a torch tensor from raw safetensors bytes WITHOUT
    going through numpy. iOS PyTorch is built with `USE_NUMPY=0`,
    so `torch.from_numpy(...)` raises 'PyTorch was compiled without
    NumPy support'. `torch.frombuffer` is the supported alternative
    — takes a bytes/bytearray directly, mirrors the dtype, returns
    a 1-D tensor we then `.view()` into the desired shape."""
    import torch
    # Map our string dtype names to actual torch dtypes.
    _TORCH_DT = {
        "float32": torch.float32, "float16": torch.float16,
        "float64": torch.float64,
        "int8":    torch.int8,    "uint8":   torch.uint8,
        "int16":   torch.int16,
        "int32":   torch.int32,
        "int64":   torch.int64,
        "bool":    torch.bool,
    }
    # bfloat16 has no numpy equivalent and torch.frombuffer can't
    # read into a bfloat16 view directly — bounce through int16.
    if torch_dtype_name == "bfloat16":
        # Make a mutable bytearray so torch.frombuffer is happy with
        # the buffer protocol on this build.
        buf = bytearray(raw_bytes)
        t_u16 = torch.frombuffer(buf, dtype=torch.int16)
        # Reinterpret the int16 bit pattern as bfloat16 (zero-copy).
        t = t_u16.view(torch.bfloat16).reshape(shape)
        return t.clone()    # detach from buffer lifetime
    # Same buffer-protocol trick for uint16/32/64 since torch
    # doesn't natively expose unsigned int>=16 — convert via int.
    if torch_dtype_name in ("uint16", "uint32", "uint64"):
        signed_name = {"uint16":"int16","uint32":"int32","uint64":"int64"}[torch_dtype_name]
        buf = bytearray(raw_bytes)
        signed_dtype = _TORCH_DT[signed_name]
        t = torch.frombuffer(buf, dtype=signed_dtype).reshape(shape)
        return t.clone()
    torch_dtype = _TORCH_DT[torch_dtype_name]
    buf = bytearray(raw_bytes)
    t = torch.frombuffer(buf, dtype=torch_dtype).reshape(shape)
    return t.clone()


def _to_numpy(raw_bytes, torch_dtype_name, shape):
    """Fall back to numpy when explicitly requested via framework='np'.
    Most callers (transformers / our shim) use the torch path, so this
    is rarely hit; but if numpy IS available we can still serve it.
    """
    try:
        import numpy as np
    except ImportError:
        raise SafetensorError("numpy not available; use framework='pt' instead")
    if torch_dtype_name == "bfloat16":
        return np.frombuffer(raw_bytes, dtype=np.uint16).copy().reshape(shape)
    return np.frombuffer(raw_bytes, dtype=np.dtype(torch_dtype_name)).copy().reshape(shape)


def safe_open(path: str, framework: str = "pt", device: str = "cpu"):
    """Drop-in replacement for safetensors.safe_open. Returns a
    context manager that exposes .keys() / .get_tensor(name) /
    .metadata() against the file."""
    _ = device   # ignored; everything lives on CPU in this shim
    return _SafeOpen(path, framework=framework)


def load_file(path: str, device: str = "cpu") -> dict:
    """Read every tensor in the file into a {name: tensor} dict.
    Equivalent to safetensors.torch.load_file."""
    _ = device
    with _SafeOpen(path, framework="pt") as f:
        return {name: f.get_tensor(name) for name in f.keys()}


# ─── writer ────────────────────────────────────────────────────────
# The on-disk format is straightforward:
#   [8 bytes : LE u64 header length N]
#   [N bytes : UTF-8 JSON header]
#   [rest   : tensor data, contiguous, in the order data_offsets implies]
#
# The header JSON is:
#   {
#     "__metadata__": { ...optional string→string... },
#     "tensor_name": {
#         "dtype":        "F32" | "F16" | "BF16" | "I8" | ...,
#         "shape":        [d0, d1, ...],
#         "data_offsets": [start_byte, end_byte]
#     },
#     ...
#   }
#
# Where offsets are RELATIVE to the start of the data section
# (8 + header_length), not absolute file offsets.

# torch dtype → safetensors dtype string
_TORCH_TO_SAFETENSOR_DTYPE = {
    # Lazily populated on first save (avoids requiring torch at import time).
}


def _build_torch_dtype_map():
    """Populate _TORCH_TO_SAFETENSOR_DTYPE on first use."""
    if _TORCH_TO_SAFETENSOR_DTYPE:
        return _TORCH_TO_SAFETENSOR_DTYPE
    import torch
    _TORCH_TO_SAFETENSOR_DTYPE.update({
        torch.float32: "F32",
        torch.float16: "F16",
        torch.bfloat16: "BF16",
        torch.float64: "F64",
        torch.int8:    "I8",
        torch.uint8:   "U8",
        torch.int16:   "I16",
        torch.int32:   "I32",
        torch.int64:   "I64",
        torch.bool:    "BOOL",
    })
    return _TORCH_TO_SAFETENSOR_DTYPE


def _tensor_to_bytes(t):
    """Extract the raw bytes of a contiguous torch tensor in its native
    dtype. Works for fp16/fp32/fp64/bf16/int*/bool. bf16 needs the
    int16 view dance because torch's untyped_storage on bf16 is iffy
    across versions."""
    import torch
    t = t.detach().cpu().contiguous()
    if t.dtype == torch.bfloat16:
        n_bytes = t.numel() * 2
        return bytes(t.view(torch.int16).untyped_storage())[:n_bytes]
    n_bytes = t.numel() * t.element_size()
    return bytes(t.untyped_storage())[:n_bytes]


def save_file(tensors: dict, path: str,
              metadata: dict | None = None) -> None:
    """Write a {name: tensor} dict to a .safetensors file.

    `metadata`, if given, is a {str: str} dict stored under the
    reserved `__metadata__` key in the header. The real safetensors
    lib enforces str/str — we do too.

    Tensor names are stored in the order they appear in the input
    dict (Python preserves insertion order since 3.7), which matters
    because data_offsets are sequential."""
    import json
    if metadata is not None:
        for k, v in metadata.items():
            if not (isinstance(k, str) and isinstance(v, str)):
                raise SafetensorError(
                    "metadata must be {str: str}; got "
                    f"{type(k).__name__}: {type(v).__name__}")

    dtype_map = _build_torch_dtype_map()

    # First pass: serialize tensors to bytes + compute offsets + header.
    header: dict = {}
    if metadata:
        header["__metadata__"] = dict(metadata)

    chunks: list[bytes] = []
    cursor = 0
    for name, t in tensors.items():
        if t.dtype not in dtype_map:
            raise SafetensorError(
                f"unsupported tensor dtype {t.dtype} for {name!r}")
        raw = _tensor_to_bytes(t)
        start = cursor
        end = cursor + len(raw)
        header[name] = {
            "dtype":        dtype_map[t.dtype],
            "shape":        list(t.shape),
            "data_offsets": [start, end],
        }
        chunks.append(raw)
        cursor = end

    # Serialize header; pad with spaces so total file is 8-byte aligned
    # past the length prefix (the real lib does the same — keeps header
    # length a multiple of 8 for readers that mmap with alignment).
    header_bytes = json.dumps(header, separators=(",", ":")).encode("utf-8")
    pad_to = 8
    extra = (-len(header_bytes)) % pad_to
    if extra:
        header_bytes += b" " * extra

    with open(path, "wb") as f:
        f.write(struct.pack("<Q", len(header_bytes)))
        f.write(header_bytes)
        for raw in chunks:
            f.write(raw)


def save(tensors: dict, metadata: dict | None = None) -> bytes:
    """In-memory variant of `save_file`. Returns the safetensors blob
    as bytes — useful for callers that mmap or stream."""
    import io, json
    dtype_map = _build_torch_dtype_map()
    header: dict = {}
    if metadata:
        header["__metadata__"] = dict(metadata)
    chunks: list[bytes] = []
    cursor = 0
    for name, t in tensors.items():
        if t.dtype not in dtype_map:
            raise SafetensorError(
                f"unsupported tensor dtype {t.dtype} for {name!r}")
        raw = _tensor_to_bytes(t)
        header[name] = {
            "dtype":        dtype_map[t.dtype],
            "shape":        list(t.shape),
            "data_offsets": [cursor, cursor + len(raw)],
        }
        chunks.append(raw)
        cursor += len(raw)
    header_bytes = json.dumps(header, separators=(",", ":")).encode("utf-8")
    extra = (-len(header_bytes)) % 8
    if extra:
        header_bytes += b" " * extra
    buf = io.BytesIO()
    buf.write(struct.pack("<Q", len(header_bytes)))
    buf.write(header_bytes)
    for raw in chunks:
        buf.write(raw)
    return buf.getvalue()


__all__ = ["__version__", "SafetensorError",
           "safe_open", "load_file", "save_file", "save"]
